"use strict";(self.webpackChunktech_far_hub=self.webpackChunktech_far_hub||[]).push([[553],{4437:function(e,t,n){n.r(t),n.d(t,{Head:function(){return h},default:function(){return u}});var r=n(1151),a=n(7294);function o(e){const t=Object.assign({ul:"ul",li:"li",h2:"h2",p:"p",em:"em",h3:"h3",a:"a"},(0,r.ah)(),e.components),{Summary:n}=t;return n||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Summary",!0),a.createElement(a.Fragment,null,a.createElement(n,null,a.createElement(t.ul,null,"\n",a.createElement(t.li,null,"Agile software development is new to the Goovernment, but has been successfully practiced in private industry for many years."),"\n",a.createElement(t.li,null,"Agile software development methods promote effective risk management through continuous testing and short feedback loops to improve outcomes on a recurring basis."),"\n")),"\n",a.createElement(t.h2,{id:"because-agile-software-development-is-a-new-process-doesnt-it-entail-more-risk"},"Because Agile software development is a new process, doesn’t it entail more risk?"),"\n",a.createElement(t.p,null,"Even though Agile software development is a new practice to the Government, it dates back to the 1970s and has been used in private industry for many years (as well as some Government agencies) where it repeatedly demonstrated a shortened time to value, enabled better adaption to changing need, and lowered the risk of project failure. These results make a compelling case to adopt Agile in federal IT projects and ensure acquisitions support these efforts. Moreover, careful selection of contract type will mitigate risk as discussed in Section E."),"\n",a.createElement(t.p,null,"For many years, private industry has realized benefits from Agile software development[",a.createElement(t.em,null,"10"),"], and some Government agencies have begun to benefit from Agile for their software development contracts. Agile software development methods promote effective risk management through continuous testing and short feedback loops to improve outcomes on a recurring basis. Because the Agile process forces problems to be identified early, failure occurs on a small scale with time for corrective action. This reduces the risk of the Government ending up with a product after a long design period that may not meet its needs or that contains unused features, or of an outright failure. In addition, use of Agile software development methods will increase focus on the development of mobile solutions, which are advantageous to today’s workforce."),"\n",a.createElement(t.h3,{id:"use-of-agile-processes-by-dods-defense-health-service-systems-to-improve-medical-readiness"},"Use of Agile Processes by DOD’s Defense Health Service Systems to Improve Medical Readiness"),"\n",a.createElement(t.p,null,"Starting in 2012, DOD used Agile (Scrum) processes to enhance the Defense Medical Human Resources System-internet (DMHRSi). This system helps to manage current and future medical human resources needs. DOD’s use of Agile processes resulted in:"),"\n",a.createElement(t.ul,null,"\n",a.createElement(t.li,null,"A reduction in the average number of days required to deliver a new software release from 419 days to 58 days (representing ~87% improvement in time to market)"),"\n",a.createElement(t.li,null,"A massive reduction in Help Desk tickets by 87%"),"\n",a.createElement(t.li,null,"Increased customer satisfaction"),"\n",a.createElement(t.li,null,"Production of a better product"),"\n"),"\n",a.createElement(t.p,null,"Reference: ",a.createElement(t.a,{href:"http://www.cecom.army.mil/THE-LINK/2014/spring/#50"},"U.S. Army Communications-Electronics Command, Spring 2014 at 48-51"),"."),"\n",a.createElement(t.p,null,"Multiple studies of the traditional “waterfall” process, where requirements are defined and documented in full detail before any testing or customer input is received, indicate a low rate of success and a high incidence of paying for features that are never used.[",a.createElement(t.em,null,"11"),"] There is also a statutory mandate to use modular contracting to the maximum extent practicable for software development that is a major system.[",a.createElement(t.em,null,"12"),"] Successful application of Agile software development, like all strategies that are newly adopted in the Government, will require training and a support structure to share best practices and lessons learned. The TechFAR Handbook and Smarter Digital Services Playbook are just one step. OMB, in close collaboration with the Chief Acquisition Officers Council, the Chief Information Officers Council, and the Acquisition Center of Excellence (ACE), will work with agencies to support these efforts."),"\n",a.createElement(t.p,null,"Acquisition personnel – and other stakeholders – should expect that Agile is a cross-functional and highly interactive process – both between agency team members and with the contractor. Therefore, IPT members – the Program/Project Managers (P/PM), IT Specialists, the Contracting Officer and/or Contract Specialist, and the Contracting Officer’s Representative (COR) – should be co-located, either virtually or in person.[",a.createElement(t.em,null,"13"),"]"),"\n",a.createElement(t.p,null,"Agile requires that the IPT learns better what the end user needs through testing[",a.createElement(t.em,null,"14"),"] and a culture that supports this approach. Therefore, P/PMs, COs, CORs, and other stakeholders need to be aware that Agile software development will not produce the final expected result with the first iteration, but instead will provide usable, working software that can be iteratively improved[",a.createElement(t.em,null,"15"),"]; it requires “touch and feel” and user feedback to get the technical features right and arrive at the final product."),"\n",a.createElement(t.h2,{id:"far-subpart-75-states-that-contractors-cannot-perform-inherently-governmental-work-because-software-requirements-are-refined-after-contract-award-would-the-use-of-a-contractor-in-an-agile-it-development-contract-be-considered-inherently-governmental"},"FAR Subpart 7.5 states that contractors cannot perform inherently Governmental work. Because software requirements are refined after contract award, would the use of a contractor in an Agile IT development contract be considered inherently Governmental?"),"\n",a.createElement(t.p,null,"Body: Using the contractor to provide assistance to the Government with Agile software development is not, in itself, inherently Governmental work. With Agile, the contractor provides suggestions for the system through a highly defined and disciplined process that is driven by user needs established and monitored by the Government."),"\n",a.createElement(t.p,null,"The use of a contractor to provide assistance to the Government with software development does not fall within the boundaries of inherently Governmental work described in OFPP Policy Letter 11-01[18] or FAR 7.503. Under Agile software development, the Government retains the responsibility for making decisions and managing the process; it plays a critical role in the IPT as the Product Owner by approving the specific plans for each iteration, establishing the priorities, approving the overall plan revisions reflecting the experience from completed iterations, and approving deliverables. As part of its responsibility, the Government is involved, at a minimum, at critical decision points in each sprint cycle – at the requirements development phase and sprint cycle review, but it is preferable to have daily involvement from the Government Product Owner, and frequent involvement from end-user representatives."),"\n",a.createElement(t.p,null,"Contractors are not involved in establishing the Product Vision or determining what overall contractual requirements are included in solicitations. They do not decide what supplies or services are acquired by the Government, which is inherently Governmental per FAR 7.503(c)(12)(i). Their focus is on helping the Government refine the software requirements (or detailed requirements) for the system through a highly defined and disciplined process that is driven by user needs established by the Government."),"\n",a.createElement(t.h2,{id:"agile-team-estimator-and-independent-government-cost-estimate-igce"},"Agile Team Estimator and Independent Government Cost Estimate (IGCE)"),"\n",a.createElement(t.p,null,a.createElement(t.a,{href:"/techfar-hub-staging-v3/branches/mattbowen-usds:v3-54-tags-pages/assets/Template%20IGCE%20-%20Agile%20Team%20Estimator.xlsx"},"For more information on how to create an estimate IGCE")))}var i=function(e){void 0===e&&(e={});const{wrapper:t}=Object.assign({},(0,r.ah)(),e.components);return t?a.createElement(t,e,a.createElement(o,e)):o(e)};var s=n(5537),l=n(8173),c=n(6861),m=n(4001);const d=e=>{let{data:t,children:n,pageContext:r}=e;return t.currentPage.frontmatter&&t.siblings&&t.currentPage.tableOfContents?a.createElement(s.Z,{frontmatter:t.currentPage.frontmatter,siblings:t.siblings,tableOfContents:t.currentPage.tableOfContents,pageContext:r,useNextLink:!0},a.createElement(l.Z,null,n)):a.createElement(c.Z,null,a.createElement("h1",null,"Something went wrong"))};function u(e){return a.createElement(d,e,a.createElement(i,e))}const h=e=>{var t;let{data:n}=e;return a.createElement(m.H,{frontmatter:null===(t=n.currentPage)||void 0===t?void 0:t.frontmatter})}}}]);
